+namespace Microsoft.Integration.Shopify;
+
+using Microsoft.Sales.Document;
+using Microsoft.Sales.History;
+using Microsoft.Utilities;
+
+/// <summary>
+/// Codeunit Shpfy Copy Document Mgt. (ID 30366).
+/// </summary>
+codeunit 30366 "Shpfy Copy Document Mgt."
+{
+    Access = Internal;
+
+    [EventSubscriber(ObjectType::Codeunit, Codeunit::"Copy Document Mgt.", 'OnCopySalesDocOnAfterTransferPostedInvoiceFields', '', false, false)]
+    local procedure ClearShopifyOrderIdOnAfterCopySalesInvoice(var ToSalesHeader: Record "Sales Header"; SalesInvoiceHeader: Record "Sales Invoice Header"; OldSalesHeader: Record "Sales Header")
+    begin
+        // Clear Shopify Order ID fields when copying from a posted invoice
+        // This ensures that when a document is copied, it is treated as a new document and not as an update to an existing Shopify order
+        ToSalesHeader."Shpfy Order Id" := 0;
+        ToSalesHeader."Shpfy Order No." := '';
+    end;
+}

